def solve(grid):
    def flips_for(rows):
        total = 0
        for row in rows:
            row = list(row)
            for a, b in zip(row, reversed(row)):
                if a != b:
                    total += 1
        return total // 2

    row_flips = flips_for(grid)
    cols = list(zip(*grid))
    col_flips = flips_for(cols)
    return min(row_flips, col_flips)


class Solution:
    def minFlips(self, grid):
        return solve(grid)

