class Solution:
    def minFlips(self, grid: List[List[int]]) -> int:
        m, n = len(grid), len(grid[0])
        row_flips = 0
        for r in range(m):
            i, j = 0, n - 1
            while i < j:
                if grid[r][i] != grid[r][j]:
                    row_flips += 1
                i += 1
                j -= 1
        col_flips = 0
        for c in range(n):
            i, j = 0, m - 1
            while i < j:
                if grid[i][c] != grid[j][c]:
                    col_flips += 1
                i += 1
                j -= 1
        return min(row_flips, col_flips)

