var minFlips = function(grid) {
    const m = grid.length, n = grid[0].length;
    let rowFlips = 0;
    for (let r = 0; r < m; r++) {
        let i = 0, j = n - 1;
        while (i < j) {
            if (grid[r][i] !== grid[r][j]) rowFlips++;
            i++;
            j--;
        }
    }
    let colFlips = 0;
    for (let c = 0; c < n; c++) {
        let i = 0, j = m - 1;
        while (i < j) {
            if (grid[i][c] !== grid[j][c]) colFlips++;
            i++;
            j--;
        }
    }
    return Math.min(rowFlips, colFlips);
};
